import { BaseNode, prop } from "@nodetool/node-sdk";
import type { NodeClass } from "@nodetool/node-sdk";
import {
  getFalApiKey,
  falSubmit,
  removeNulls,
  isRefSet,
  assetToFalUrl,
  imageToDataUrl
} from "../fal-base.js";

// Re-export alias
const FalNode = BaseNode;

export class FluxSchnellRedux extends FalNode {
  static readonly nodeType = "fal.image_to_image.FluxSchnellRedux";
  static readonly title = "Flux Schnell Redux";
  static readonly description = `FLUX.1 [schnell] Redux enables rapid transformation of existing images with high-quality style transfers and modifications using the fast FLUX.1 schnell model.
image, transformation, style-transfer, fast, flux, redux`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = {
    prompt: "str",
    images: "list[Image]",
    timings: "dict[str, any]",
    has_nsfw_concepts: "list[bool]",
    seed: "int"
  };

  @prop({
    type: "int",
    default: 1,
    description: "The number of images to generate (1-4)"
  })
  declare num_images: any;

  @prop({
    type: "enum",
    default: "landscape_4_3",
    description: "The size of the generated image"
  })
  declare image_size: any;

  @prop({
    type: "enum",
    default: "none",
    values: ["none", "regular", "high"],
    description: "Acceleration speed: 'none', 'regular', or 'high'"
  })
  declare acceleration: any;

  @prop({
    type: "enum",
    default: "jpeg",
    values: ["jpeg", "png"],
    description: "Output format (jpeg or png)"
  })
  declare output_format: any;

  @prop({
    type: "image",
    default: "",
    description: "The input image to transform"
  })
  declare image: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "If 'True', the media will be returned as a data URI and the output data won't be available in the request history."
  })
  declare sync_mode: any;

  @prop({
    type: "bool",
    default: true,
    description: "Enable safety checker to filter unsafe content"
  })
  declare enable_safety_checker: any;

  @prop({
    type: "int",
    default: -1,
    description: "Seed for reproducible results. Use -1 for random"
  })
  declare seed: any;

  @prop({
    type: "int",
    default: 4,
    description: "The number of inference steps to perform (1-50)"
  })
  declare num_inference_steps: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const numImages = Number(this.num_images ?? 1);
    const imageSize = String(this.image_size ?? "landscape_4_3");
    const acceleration = String(this.acceleration ?? "none");
    const outputFormat = String(this.output_format ?? "jpeg");
    const syncMode = Boolean(this.sync_mode ?? false);
    const enableSafetyChecker = Boolean(this.enable_safety_checker ?? true);
    const seed = Number(this.seed ?? -1);
    const numInferenceSteps = Number(this.num_inference_steps ?? 4);

    const args: Record<string, unknown> = {
      num_images: numImages,
      image_size: imageSize,
      acceleration: acceleration,
      output_format: outputFormat,
      sync_mode: syncMode,
      enable_safety_checker: enableSafetyChecker,
      seed: seed,
      num_inference_steps: numInferenceSteps
    };

    const imageRef = this.image as Record<string, unknown> | undefined;
    if (isRefSet(imageRef)) {
      const imageUrl =
        (await imageToDataUrl(imageRef!)) ??
        (await assetToFalUrl(apiKey, imageRef!));
      if (imageUrl) args["image_url"] = imageUrl;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/flux/schnell/redux", args);
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

