export class IdeogramV2Edit extends FalNode {
  static readonly nodeType = "fal.image_to_image.IdeogramV2Edit";
  static readonly title = "Ideogram V2 Edit";
  static readonly description = `Transform existing images with Ideogram V2's editing capabilities. Modify, adjust, and refine images while maintaining high fidelity with precise prompt and mask control.
image, editing, inpainting, mask, ideogram, transformation`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = { images: "list[File]", seed: "int" };

  @prop({
    type: "str",
    default: "",
    description: "The prompt to fill the masked part of the image"
  })
  declare prompt: any;

  @prop({
    type: "enum",
    default: "auto",
    values: ["auto", "general", "realistic", "design", "render_3D", "anime"],
    description:
      "Style of generated image (auto, general, realistic, design, render_3D, anime)"
  })
  declare style: any;

  @prop({
    type: "bool",
    default: true,
    description: "Whether to expand the prompt with MagicPrompt functionality"
  })
  declare expand_prompt: any;

  @prop({ type: "image", default: "", description: "The image to edit" })
  declare image: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "If 'True', the media will be returned as a data URI and the output data won't be available in the request history."
  })
  declare sync_mode: any;

  @prop({
    type: "int",
    default: -1,
    description: "Seed for reproducible results. Use -1 for random"
  })
  declare seed: any;

  @prop({
    type: "image",
    default: "",
    description:
      "The mask URL to inpaint the image. Needs to match the dimensions of the input image."
  })
  declare mask_url: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const prompt = String(this.prompt ?? "");
    const style = String(this.style ?? "auto");
    const expandPrompt = Boolean(this.expand_prompt ?? true);
    const syncMode = Boolean(this.sync_mode ?? false);
    const seed = Number(this.seed ?? -1);

    const args: Record<string, unknown> = {
      prompt: prompt,
      style: style,
      expand_prompt: expandPrompt,
      sync_mode: syncMode,
      seed: seed
    };

    const imageRef = this.image as Record<string, unknown> | undefined;
    if (isRefSet(imageRef)) {
      const imageUrl =
        (await imageToDataUrl(imageRef!)) ??
        (await assetToFalUrl(apiKey, imageRef!));
      if (imageUrl) args["image_url"] = imageUrl;
    }

    const maskUrlRef = this.mask_url as Record<string, unknown> | undefined;
    if (isRefSet(maskUrlRef)) {
      const maskUrlUrl =
        (await imageToDataUrl(maskUrlRef!)) ??
        (await assetToFalUrl(apiKey, maskUrlRef!));
      if (maskUrlUrl) args["mask_url"] = maskUrlUrl;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/ideogram/v2/edit", args);
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

