export class BriaFiboEdit extends FalNode {
  static readonly nodeType = "fal.image_to_image.BriaFiboEdit";
  static readonly title = "Bria Fibo Edit";
  static readonly description = `Bria FIBO Edit provides general-purpose image editing with AI-powered modifications and enhancements.
image, editing, bria, fibo, general`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = {
    images: "list[Image]",
    image: "image",
    structured_instruction: "dict[str, any]"
  };

  @prop({ type: "int", default: 30, description: "Number of inference steps." })
  declare steps_num: any;

  @prop({
    type: "str",
    default: "",
    description: "The original vgl used to generate the image."
  })
  declare original_vgl: any;

  @prop({
    type: "str",
    default: "",
    description: "Instruction for image editing."
  })
  declare instruction: any;

  @prop({
    type: "image",
    default: "",
    description: "Reference image (file or URL)."
  })
  declare image: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "If true, returns the image directly in the response (increases latency)."
  })
  declare sync_mode: any;

  @prop({ type: "str", default: 5, description: "Guidance scale for text." })
  declare guidance_scale: any;

  @prop({
    type: "str",
    default: "",
    description: "The structured prompt to generate an image from."
  })
  declare structured_instruction: any;

  @prop({
    type: "image",
    default: "",
    description: "Mask image (file or URL). Optional"
  })
  declare mask_url: any;

  @prop({
    type: "str",
    default: "",
    description: "Negative prompt for image generation."
  })
  declare negative_prompt: any;

  @prop({
    type: "int",
    default: 5555,
    description: "Random seed for reproducibility."
  })
  declare seed: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const stepsNum = Number(this.steps_num ?? 30);
    const originalVgl = String(this.original_vgl ?? "");
    const instruction = String(this.instruction ?? "");
    const syncMode = Boolean(this.sync_mode ?? false);
    const guidanceScale = String(this.guidance_scale ?? 5);
    const structuredInstruction = String(this.structured_instruction ?? "");
    const negativePrompt = String(this.negative_prompt ?? "");
    const seed = Number(this.seed ?? 5555);

    const args: Record<string, unknown> = {
      steps_num: stepsNum,
      original_vgl: originalVgl,
      instruction: instruction,
      sync_mode: syncMode,
      guidance_scale: guidanceScale,
      structured_instruction: structuredInstruction,
      negative_prompt: negativePrompt,
      seed: seed
    };

    const imageRef = this.image as Record<string, unknown> | undefined;
    if (isRefSet(imageRef)) {
      const imageUrl =
        (await imageToDataUrl(imageRef!)) ??
        (await assetToFalUrl(apiKey, imageRef!));
      if (imageUrl) args["image_url"] = imageUrl;
    }

    const maskUrlRef = this.mask_url as Record<string, unknown> | undefined;
    if (isRefSet(maskUrlRef)) {
      const maskUrlUrl =
        (await imageToDataUrl(maskUrlRef!)) ??
        (await assetToFalUrl(apiKey, maskUrlRef!));
      if (maskUrlUrl) args["mask_url"] = maskUrlUrl;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "bria/fibo-edit/edit", args);
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

