export class Wan25PreviewImageToImage extends FalNode {
  static readonly nodeType = "fal.image_to_image.Wan25PreviewImageToImage";
  static readonly title = "Wan25 Preview Image To Image";
  static readonly description = `Wan 2.5 Image to Image
editing, transformation, image-to-image, img2img`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = {
    seeds: "list[int]",
    images: "list[ImageFile]",
    actual_prompt: "str"
  };

  @prop({
    type: "str",
    default: "",
    description:
      "The text prompt describing how to edit the image. Max 2000 characters."
  })
  declare prompt: any;

  @prop({
    type: "int",
    default: 1,
    description: "Number of images to generate. Values from 1 to 4."
  })
  declare num_images: any;

  @prop({
    type: "str",
    default: "square",
    description:
      "The size of the generated image. Width and height must be between 384 and 1440 pixels."
  })
  declare image_size: any;

  @prop({
    type: "bool",
    default: true,
    description: "If set to true, the safety checker will be enabled."
  })
  declare enable_safety_checker: any;

  @prop({
    type: "str",
    default: "",
    description:
      "Random seed for reproducibility. If None, a random seed is chosen."
  })
  declare seed: any;

  @prop({
    type: "list[image]",
    default: [],
    description:
      "URLs of images to edit. For single-image editing, provide 1 URL. For multi-reference generation, provide up to 2 URLs. If more than 2 URLs are provided, only the first 2 will be used."
  })
  declare images: any;

  @prop({
    type: "str",
    default: "",
    description:
      "Negative prompt to describe content to avoid. Max 500 characters."
  })
  declare negative_prompt: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const prompt = String(this.prompt ?? "");
    const numImages = Number(this.num_images ?? 1);
    const imageSize = String(this.image_size ?? "square");
    const enableSafetyChecker = Boolean(this.enable_safety_checker ?? true);
    const seed = String(this.seed ?? "");
    const negativePrompt = String(this.negative_prompt ?? "");

    const args: Record<string, unknown> = {
      prompt: prompt,
      num_images: numImages,
      image_size: imageSize,
      enable_safety_checker: enableSafetyChecker,
      seed: seed,
      negative_prompt: negativePrompt
    };

    const imagesList = this.images as Record<string, unknown>[] | undefined;
    if (imagesList?.length) {
      const imagesUrls: string[] = [];
      for (const ref of imagesList) {
        if (isRefSet(ref)) {
          const u = await assetToFalUrl(apiKey, ref);
          if (u) imagesUrls.push(u);
        }
      }
      if (imagesUrls.length) args["image_urls"] = imagesUrls;
    }
    removeNulls(args);

    const res = await falSubmit(
      apiKey,
      "fal-ai/wan-25-preview/image-to-image",
      args
    );
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

