export class Rife extends FalNode {
  static readonly nodeType = "fal.image_to_image.Rife";
  static readonly title = "Rife";
  static readonly description = `RIFE
editing, transformation, image-to-image, img2img`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = { images: "list[Image]", video: "video" };

  @prop({
    type: "enum",
    default: "jpeg",
    values: ["png", "jpeg"],
    description:
      "The format of the output images. Only applicable if output_type is 'images'."
  })
  declare output_format: any;

  @prop({
    type: "int",
    default: 8,
    description:
      "Frames per second for the output video. Only applicable if output_type is 'video'."
  })
  declare fps: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "If 'True', the media will be returned as a data URI and the output data won't be available in the request history."
  })
  declare sync_mode: any;

  @prop({
    type: "bool",
    default: false,
    description: "Whether to include the end image in the output."
  })
  declare include_end: any;

  @prop({
    type: "bool",
    default: false,
    description: "Whether to include the start image in the output."
  })
  declare include_start: any;

  @prop({
    type: "int",
    default: 1,
    description: "The number of frames to generate between the input images."
  })
  declare num_frames: any;

  @prop({
    type: "image",
    default: "",
    description:
      "The URL of the second image to use as the ending point for interpolation."
  })
  declare end_image: any;

  @prop({
    type: "image",
    default: "",
    description:
      "The URL of the first image to use as the starting point for interpolation."
  })
  declare start_image: any;

  @prop({
    type: "enum",
    default: "images",
    values: ["images", "video"],
    description:
      "The type of output to generate; either individual images or a video."
  })
  declare output_type: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const outputFormat = String(this.output_format ?? "jpeg");
    const fps = Number(this.fps ?? 8);
    const syncMode = Boolean(this.sync_mode ?? false);
    const includeEnd = Boolean(this.include_end ?? false);
    const includeStart = Boolean(this.include_start ?? false);
    const numFrames = Number(this.num_frames ?? 1);
    const outputType = String(this.output_type ?? "images");

    const args: Record<string, unknown> = {
      output_format: outputFormat,
      fps: fps,
      sync_mode: syncMode,
      include_end: includeEnd,
      include_start: includeStart,
      num_frames: numFrames,
      output_type: outputType
    };

    const endImageRef = this.end_image as Record<string, unknown> | undefined;
    if (isRefSet(endImageRef)) {
      const endImageUrl =
        (await imageToDataUrl(endImageRef!)) ??
        (await assetToFalUrl(apiKey, endImageRef!));
      if (endImageUrl) args["end_image_url"] = endImageUrl;
    }

    const startImageRef = this.start_image as
      | Record<string, unknown>
      | undefined;
    if (isRefSet(startImageRef)) {
      const startImageUrl =
        (await imageToDataUrl(startImageRef!)) ??
        (await assetToFalUrl(apiKey, startImageRef!));
      if (startImageUrl) args["start_image_url"] = startImageUrl;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/rife", args);
    return { output: { type: "video", uri: (res.video as any).url } };
  }
}

