      face_enhancement_strength: faceEnhancementStrength,
      sharpen: sharpen,
      detail: detail,
      denoise: denoise,
      output_format: outputFormat,
      subject_detection: subjectDetection,
      strength: strength,
      texture: texture,
      autoprompt: autoprompt,
