export class ImageEditingCartoonify extends FalNode {
  static readonly nodeType = "fal.image_to_image.ImageEditingCartoonify";
  static readonly title = "Image Editing Cartoonify";
  static readonly description = `Transform your photos into vibrant cool cartoons with bold outlines and rich colors.
editing, transformation, image-to-image, img2img`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = { images: "list[Image]", seed: "int" };

  @prop({
    type: "str",
    default: "",
    description: "The aspect ratio of the generated image."
  })
  declare aspect_ratio: any;

  @prop({
    type: "enum",
    default: "jpeg",
    values: ["jpeg", "png"],
    description: "The format of the generated image."
  })
  declare output_format: any;

  @prop({
    type: "image",
    default: "",
    description: "Image prompt for the omni model."
  })
  declare image: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "If 'True', the media will be returned as a data URI and the output data won't be available in the request history."
  })
  declare sync_mode: any;

  @prop({
    type: "enum",
    default: "2",
    values: ["1", "2", "3", "4", "5", "6"],
    description:
      "The safety tolerance level for the generated image. 1 being the most strict and 6 being the most permissive."
  })
  declare safety_tolerance: any;

  @prop({
    type: "float",
    default: 3.5,
    description:
      "The CFG (Classifier Free Guidance) scale is a measure of how close you want the model to stick to your prompt when looking for a related image to show you."
  })
  declare guidance_scale: any;

  @prop({
    type: "str",
    default: "",
    description:
      "The same seed and the same prompt given to the same version of the model will output the same image every time."
  })
  declare seed: any;

  @prop({
    type: "int",
    default: 30,
    description: "Number of inference steps for sampling."
  })
  declare num_inference_steps: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const aspectRatio = String(this.aspect_ratio ?? "");
    const outputFormat = String(this.output_format ?? "jpeg");
    const syncMode = Boolean(this.sync_mode ?? false);
    const safetyTolerance = String(this.safety_tolerance ?? "2");
    const guidanceScale = Number(this.guidance_scale ?? 3.5);
    const seed = String(this.seed ?? "");
    const numInferenceSteps = Number(this.num_inference_steps ?? 30);

    const args: Record<string, unknown> = {
      aspect_ratio: aspectRatio,
      output_format: outputFormat,
      sync_mode: syncMode,
      safety_tolerance: safetyTolerance,
      guidance_scale: guidanceScale,
      seed: seed,
      num_inference_steps: numInferenceSteps
    };

    const imageRef = this.image as Record<string, unknown> | undefined;
    if (isRefSet(imageRef)) {
      const imageUrl =
        (await imageToDataUrl(imageRef!)) ??
        (await assetToFalUrl(apiKey, imageRef!));
      if (imageUrl) args["image_url"] = imageUrl;
    }
    removeNulls(args);

    const res = await falSubmit(
      apiKey,
      "fal-ai/image-editing/cartoonify",
      args
    );
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

