    const moderationLevel = String(this.moderation_level ?? "permissive");
    const garmentPhotoType = String(this.garment_photo_type ?? "auto");
    const garmentImage = String(this.garment_image ?? "");
    const category = String(this.category ?? "auto");
    const syncMode = Boolean(this.sync_mode ?? false);
    const segmentationFree = Boolean(this.segmentation_free ?? true);
    const numSamples = Number(this.num_samples ?? 1);
    const mode = String(this.mode ?? "balanced");
    const seed = String(this.seed ?? "");
    const outputFormat = String(this.output_format ?? "png");

    const args: Record<string, unknown> = {
      model_image: modelImage,
      moderation_level: moderationLevel,
      garment_photo_type: garmentPhotoType,
      garment_image: garmentImage,
      category: category,
      sync_mode: syncMode,
      segmentation_free: segmentationFree,
      num_samples: numSamples,
      mode: mode,
      seed: seed,
      output_format: outputFormat
    };
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/fashn/tryon/v1.5", args);
