export class GeminiFlashEditMulti extends FalNode {
  static readonly nodeType = "fal.image_to_image.GeminiFlashEditMulti";
  static readonly title = "Gemini Flash Edit Multi";
  static readonly description = `Gemini Flash Edit Multi Image is a model that can edit multiple images using a text prompt and a reference image.
editing, transformation, image-to-image, img2img`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = { description: "str", image: "image" };

  @prop({
    type: "str",
    default: "",
    description: "The prompt for image generation or editing"
  })
  declare prompt: any;

  @prop({
    type: "list[image]",
    default: [],
    description: "List of URLs of input images for editing"
  })
  declare input_images: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const prompt = String(this.prompt ?? "");

    const args: Record<string, unknown> = {
      prompt: prompt
    };

    const inputImagesList = this.input_images as
      | Record<string, unknown>[]
      | undefined;
    if (inputImagesList?.length) {
      const inputImagesUrls: string[] = [];
      for (const ref of inputImagesList) {
        if (isRefSet(ref)) {
          const u = await assetToFalUrl(apiKey, ref);
          if (u) inputImagesUrls.push(u);
        }
      }
      if (inputImagesUrls.length) args["input_image_urls"] = inputImagesUrls;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/gemini-flash-edit/multi", args);
    return res as Record<string, unknown>;
  }
}

