export class EvfSam extends FalNode {
  static readonly nodeType = "fal.image_to_image.EvfSam";
  static readonly title = "Evf Sam";
  static readonly description = `EVF-SAM2 combines natural language understanding with advanced segmentation capabilities, allowing you to precisely mask image regions using intuitive positive and negative text prompts.
editing, transformation, image-to-image, img2img`;
  static readonly requiredSettings = ["FAL_API_KEY"];
  static readonly outputTypes = { image: "image" };

  @prop({
    type: "str",
    default: "",
    description: "The prompt to generate segmentation from."
  })
  declare prompt: any;

  @prop({
    type: "bool",
    default: false,
    description: "Use GroundingDINO instead of SAM for segmentation"
  })
  declare use_grounding_dino: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "Enable semantic level segmentation for body parts, background or multi objects"
  })
  declare semantic_type: any;

  @prop({
    type: "bool",
    default: false,
    description: "Fill holes in the mask using morphological operations"
  })
  declare fill_holes: any;

  @prop({
    type: "int",
    default: 0,
    description: "Expand/dilate the mask by specified pixels"
  })
  declare expand_mask: any;

  @prop({
    type: "bool",
    default: true,
    description: "Output only the binary mask instead of masked image"
  })
  declare mask_only: any;

  @prop({
    type: "bool",
    default: false,
    description:
      "Invert the mask (background becomes foreground and vice versa)"
  })
  declare revert_mask: any;

  @prop({
    type: "int",
    default: 0,
    description:
      "Apply Gaussian blur to the mask. Value determines kernel size (must be odd number)"
  })
  declare blur_mask: any;

  @prop({
    type: "str",
    default: "",
    description:
      "Areas to exclude from segmentation (will be subtracted from prompt results)"
  })
  declare negative_prompt: any;

  @prop({ type: "image", default: "", description: "URL of the input image" })
  declare image: any;

  async process(): Promise<Record<string, unknown>> {
    const apiKey = getFalApiKey(this._secrets);
    const prompt = String(this.prompt ?? "");
    const useGroundingDino = Boolean(this.use_grounding_dino ?? false);
    const semanticType = Boolean(this.semantic_type ?? false);
    const fillHoles = Boolean(this.fill_holes ?? false);
    const expandMask = Number(this.expand_mask ?? 0);
    const maskOnly = Boolean(this.mask_only ?? true);
    const revertMask = Boolean(this.revert_mask ?? false);
    const blurMask = Number(this.blur_mask ?? 0);
    const negativePrompt = String(this.negative_prompt ?? "");

    const args: Record<string, unknown> = {
      prompt: prompt,
      use_grounding_dino: useGroundingDino,
      semantic_type: semanticType,
      fill_holes: fillHoles,
      expand_mask: expandMask,
      mask_only: maskOnly,
      revert_mask: revertMask,
      blur_mask: blurMask,
      negative_prompt: negativePrompt
    };

    const imageRef = this.image as Record<string, unknown> | undefined;
    if (isRefSet(imageRef)) {
      const imageUrl =
        (await imageToDataUrl(imageRef!)) ??
        (await assetToFalUrl(apiKey, imageRef!));
      if (imageUrl) args["image_url"] = imageUrl;
    }
    removeNulls(args);

    const res = await falSubmit(apiKey, "fal-ai/evf-sam", args);
    const images = res.images as { url: string }[];
    return { output: { type: "image", uri: images[0].url } };
  }
}

